  ngOnInit(): void {
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    this.SortForm = this.formBuilder.group({
      groupSort: new FormControl(this.groupSortVal),
    });
    this.SearchForm = this.formBuilder.group({
      search_input: new FormControl(""),
    });
    this.permissionDateForm = this.formBuilder.group({
      startDate: ["", [Validators.required]],
      endDate: ["", [Validators.required]],
      workingDays: [""],
    });
    this.permissionTimeForm = this.formBuilder.group({
      startTime: ["", [Validators.required]],
      endTime: ["", [Validators.required]],
    });
    this.getGroups();
  }

  ngOnDestroy(): void {}

  getGroups(): void {
    console.log(this.SearchForm.controls);
    this.showLoader = true;
    this.initialLoad = false;
    this.http
      .post<any>(this.env.API_URL + `api/Permissions/GetGroups`, {
        page: this.page,
        pageSize: this.pageSize,
        searchString: this.SearchForm.controls.search_input.value,
        groupSort: this.groupSortVal,
      })
      .subscribe({
        next: (data) => {
          this.groups = data.entities;
          this.resultsCount = data.totalCount;
          let x = data.totalCount / this.pageSize;
          this.totalPages =
            Math.trunc(x) < data.totalCount / this.pageSize
              ? Math.trunc(x) + 1
              : Math.trunc(x);
          if (this.groups.length > 0) {
            this.noResults = false;
            if (this.groups.length == 1 && this.totalPages == 1) {
            }
          } else {
            this.noResults = true;
          }
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  search(): void {}
  pageSize: number; // number of viewed results
  page = 1; // the page we are viewing
  resultsCount; // the nuber of results
  totalPages = 1; // calculate by the pageSize and resultcount this.totalPages = (Math.trunc(x) < (this.resultsCount/this.pageSize)) ? Math.trunc(x)+1:Math.trunc(x) ;

  goLast() {
    if (this.page != this.totalPages) {
      this.page = this.totalPages;
    }
  }
  nextPage() {
    if (this.totalPages > this.page) {
      this.page++;
    }
  }
  prevPage() {
    if (this.page > 1) {
      this.page--;
    }
  }
  goFirst() {
    if (this.page != 1) {
      this.page = 1;
    }
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }
  groupSelected(group: Group): void {
    this.selectedGroup = group;
    this.showLoader = true;
    console.log(this.selectedGroup);
    this.http
      .post<Permission[]>(
        this.env.API_URL + `api/Permissions/GetGroupPermissions`,
        group
      )
      .subscribe({
        next: (data) => {
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  ChangePermission(permission: Permission, value: number): void {
    this.showLoader = true;
    var changedPermission: Permission = {
      feature_description: permission.feature_description,
      feature_name: permission.feature_name,
      feature_number: permission.feature_number,
      feature_type: permission.feature_type,
      permission: value,
      branch_code: permission.branch_code,
      org_code: permission.org_code,
      group_code: permission.group_code,
      group_name: this.selectedGroup.group_name,
      work_end_date: permission.work_end_date,
      work_start_date: permission.work_start_date,
      working_days: permission.working_days,
      work_start_time: permission.work_start_time,
      work_end_time: permission.work_end_time,
    };
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetGroupPermission`,
        changedPermission
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  async ChangePermissions(permissions: Permission[], value: number) {
    this.showLoader = true;
    var newPermissions: Permission[] = [];
    permissions.forEach((permission) => {
      var changedPermission: Permission = {
        feature_description: permission.feature_description,
        feature_name: permission.feature_name,
        feature_number: permission.feature_number,
        feature_type: permission.feature_type,
        permission: value,
        branch_code: permission.branch_code,
        org_code: permission.org_code,
        group_code: permission.group_code,
        group_name: this.selectedGroup.group_name,
        work_end_date: permission.work_end_date,
        work_start_date: permission.work_start_date,
        working_days: permission.working_days,
        work_start_time: permission.work_start_time,
        work_end_time: permission.work_end_time,
      };
      newPermissions.push(changedPermission);
    });
    var alertText = value == 1 ? "منح" : "إلغاء";
    if (
      permissions.length > 0 &&
      !(await this.alertService.SaveAlert(
        `هل تريد ${alertText} جميع الصلاحيات؟`
      ))
    ) {
      this.showLoader = false;
      return;
    }
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetGroupPermissions`,
        newPermissions
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
